<template>
  <view class="page"><StatisticsHeader @refresh="refresh" @export="handleExport" /><view class="content"><view class="ranges"><view class="r" :class="{active:activeRange==='today'}" @click="handleRangeChange('today')">今日</view><view class="r" :class="{active:activeRange==='week'}" @click="handleRangeChange('week')">本周</view><view class="r" :class="{active:activeRange==='month'}" @click="handleRangeChange('month')">本月</view><view class="r" :class="{active:activeRange==='quarter'}" @click="handleRangeChange('quarter')">近90天</view></view><view class="core" v-if="dashboard"><view class="idx">{{ dashboard.coreMetrics.operationIndex }}</view><view class="m"><text>本月收益 ¥{{ dashboard.coreMetrics.monthlyProfit }}</text><text>新增会员 {{ dashboard.coreMetrics.newMemberCount }}</text><text>进行中项目 {{ dashboard.coreMetrics.activeProjectCount }}</text><text>活动报名 {{ dashboard.coreMetrics.activitySignupCount }}</text><text>待处理 {{ dashboard.coreMetrics.pendingTodoCount }}</text></view></view><view class="panel"><view class="tabs"><view v-for="t in dashboard?.trendTabs||[]" :key="t.key" class="tab" :class="{active:activeTrendType===t.key}" @click="handleTrendTypeChange(t.key)">{{ t.label }}</view></view><svg viewBox="0 0 300 120" class="chart"><polyline :points="points" fill="none" stroke="#2f6dff" stroke-width="3"/></svg></view><view class="panel"><text class="h">业务分布</text><view v-for="d in dashboard?.distribution||[]" :key="d.key" class="row"><text>{{ d.label }}</text><text>{{ d.value }}%</text></view></view><view class="panel"><text class="h">数据洞察</text><view v-for="i in dashboard?.insights||[]" :key="i.id" class="row" @click="handleInsightClick(i)"><text>{{ i.title }}</text><text class="link">查看</text></view></view><view class="panel"><text class="h">模块排行</text><view class="tabs"><view class="tab" :class="{active:activeRankingType==='project'}" @click="handleRankingTypeChange('project')">项目</view><view class="tab" :class="{active:activeRankingType==='activity'}" @click="handleRankingTypeChange('activity')">活动</view><view class="tab" :class="{active:activeRankingType==='all'}" @click="handleRankingTypeChange('all')">全部</view></view><view v-for="(r,idx) in currentRankingList" :key="r.id" class="row" @click="handleQuickJump(r.path)"><text>{{ idx+1 }} {{ r.name }}</text><text>{{ r.trend }}</text></view></view><view class="quick panel"><text class="h">快捷查看</text><view class="qgrid"><view class="q" @click="handleQuickJump('/pages/project/list')">项目</view><view class="q" @click="handleQuickJump('/pages/activity/index')">活动</view><view class="q" @click="handleQuickJump('/pages/member/index')">会员</view><view class="q" @click="handleQuickJump('/pages/apply/index')">入驻</view><view class="q" @click="handleQuickJump('/pages/finance/index')">财务</view><view class="q" @click="handleQuickJump('/pages/tools/export')">导出</view></view></view><SkeletonBlock v-if="pageState==='skeleton'" :rows="6" /><PageState v-else-if="pageState==='error'" state="error" title="加载失败" description="请稍后重试" action-text="重试" @retry="reload" /></view></view>
</template>
<script setup>
import { computed, onMounted } from 'vue'
import { useStatisticsDashboard } from '../../hooks/useStatisticsDashboard'
import StatisticsHeader from './components/StatisticsHeader.vue'
import SkeletonBlock from '../../components/state/SkeletonBlock.vue'
import PageState from '../../components/state/PageState.vue'
const { dashboard, activeRange, activeTrendType, activeRankingType, currentTrendSeries, currentRankingList, pageState, reload, refresh, handleRangeChange, handleTrendTypeChange, handleRankingTypeChange, handleInsightClick, handleQuickJump, handleExport } = useStatisticsDashboard()
const points = computed(()=>{const s=currentTrendSeries.value||[]; if(!s.length) return ''; const max=Math.max(...s.map(i=>i.value)); return s.map((it,idx)=>`${20+idx*(260/Math.max(1,s.length-1))},${100-(it.value/max)*70}`).join(' ')})
onMounted(reload)
</script>
<style scoped>
.page{min-height:100vh;background:#f5f7fb}.content{padding:20rpx 24rpx;display:flex;flex-direction:column;gap:12rpx}.ranges{display:flex;background:#edf1f8;border-radius:999rpx;padding:6rpx}.r{flex:1;text-align:center;padding:10rpx 0;border-radius:999rpx;color:#6d7890;font-size:22rpx}.r.active{background:#245bff;color:#fff}.core{background:linear-gradient(135deg,#2f6dff,#4f88ff);border-radius:18rpx;padding:16rpx;color:#fff;display:flex;gap:16rpx}.idx{width:120rpx;height:120rpx;border-radius:999rpx;border:8rpx solid rgba(255,255,255,.35);display:flex;align-items:center;justify-content:center;font-size:42rpx;font-weight:700}.m{display:grid;grid-template-columns:1fr;gap:4rpx;font-size:22rpx}.panel{background:#fff;border-radius:16rpx;padding:14rpx}.tabs{display:flex;gap:10rpx;overflow:auto}.tab{padding:8rpx 12rpx;border-radius:999rpx;background:#eef2fb;color:#5f6d86;font-size:22rpx}.tab.active{background:#245bff;color:#fff}.chart{width:100%;height:220rpx;margin-top:8rpx}.h{font-size:26rpx;font-weight:700;color:#172033}.row{display:flex;justify-content:space-between;padding:10rpx 0;border-bottom:1rpx solid #eef2f8;font-size:23rpx}.row:last-child{border-bottom:0}.link{color:#245bff}.qgrid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:10rpx;margin-top:10rpx}.q{padding:12rpx;text-align:center;background:#f1f5ff;border-radius:10rpx;color:#245bff}
</style>
